	"default-safe-outputs": {"defaults", "dev-tools", "github", "local"},
}

// ecosystemParents defines ecosystem inheritance for runtimes that use another
// ecosystem's package repositories in addition to their own tooling domains.
var ecosystemParents = map[string][]string{
	"scala": {"java"},
}

// getEcosystemDomains returns the domains for a given ecosystem category.
// Supports compound ecosystem identifiers (see compoundEcosystems).
// The returned list is sorted and contains unique entries.
func getEcosystemDomains(category string) []string {
	return getEcosystemDomainsWithSeen(category, map[string]bool{})
}

func getEcosystemDomainsWithSeen(category string, seen map[string]bool) []string {
	if seen[category] {
		return []string{}
	}
	seen[category] = true

	domainMap := make(map[string]bool)

	if components, ok := compoundEcosystems[category]; ok {
		for _, component := range components {
			for _, d := range getEcosystemDomainsWithSeen(component, seen) {
				domainMap[d] = true
			}
		}
		return sortedDomainKeys(domainMap)
	}

	for _, parent := range ecosystemParents[category] {
		for _, d := range getEcosystemDomainsWithSeen(parent, seen) {
			domainMap[d] = true
		}
	}

	for _, d := range ecosystemDomains[category] {
		domainMap[d] = true
	}

	return sortedDomainKeys(domainMap)
}

func sortedDomainKeys(domainMap map[string]bool) []string {
	result := make([]string, 0, len(domainMap))
	for d := range domainMap {
		result = append(result, d)
	}
	sort.Strings(result)
	return result
}

